import{_ as a,o as i,i as o,aF as l}from"./chunks/framework.BgOcWNcQ.js";const h=JSON.parse('{"title":"ka-page-optimizer","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills/ka-page-optimizer.md","filePath":"guide/skills/ka-page-optimizer.md"}'),d={name:"guide/skills/ka-page-optimizer.md"};function t(s,e,p,c,n,r){return i(),o("div",null,[...e[0]||(e[0]=[l(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/skills/ka-page-optimizer.md for this page in Markdown format</div><h1 id="ka-page-optimizer" tabindex="-1">ka-page-optimizer <a class="header-anchor" href="#ka-page-optimizer" aria-label="Permalink to &quot;ka-page-optimizer&quot;">​</a></h1><p><code>ka-page-optimizer</code> 用来重构已经存在的 Vue 页面。它会优先使用 Kpu-admin 内建的 <code>Ka*</code> 组件和工具函数，替换原生 HTML、重复造轮子的自定义实现，以及风格不统一的页面壳层，在尽量不改业务逻辑的前提下，把页面拉回框架统一的交互和视觉体系。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>页面结构太乱、风格不统一</li><li>页面里有大量原生 HTML 或重复自定义实现</li><li>希望用框架内建 <code>Ka*</code> 组件替换现有实现</li><li>希望保留现有接口、权限和业务逻辑，只优化视图层与页面结构</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><p>直接说明以下信息即可：</p><ul><li>目标应用，例如 <code>example</code></li><li>需要优化的页面文件或目录</li><li>希望替换或优化的内容，例如搜索区、卡片容器、弹窗、分页、空态、加载状态</li><li>是否允许顺手拆分子组件或整理模板结构</li><li>是否要求不改业务逻辑</li></ul><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>在 example 应用里优化用户列表页。</span></span>
<span class="line"><span>文件是 apps/example/src/views/system/user/index.vue。</span></span>
<span class="line"><span>把原生按钮、搜索区域、分页和删除确认弹窗替换成 Ka 组件，不要改业务逻辑。</span></span></code></pre></div><h2 id="常见优化内容" tabindex="-1">常见优化内容 <a class="header-anchor" href="#常见优化内容" aria-label="Permalink to &quot;常见优化内容&quot;">​</a></h2><ul><li>用 <code>KaCard</code> 收敛页面容器、标题区、操作区和底部区域</li><li>用 <code>KaSearchBar</code> 替换手写搜索表单或零散筛选输入</li><li>用 <code>KaButton</code>、<code>KaButtonGroup</code> 统一操作按钮的样式、尺寸和状态</li><li>用 <code>KaModal</code>、<code>KaDrawer</code>、<code>useKaModal()</code> 替换自定义弹层与确认逻辑</li><li>用 <code>KaPagination</code>、<code>KaEmpty</code>、<code>KaLoading</code>、<code>useKaLoading()</code> 统一列表状态</li><li>用 <code>useKaToast()</code> 替换零散的成功、失败、警告提示调用</li></ul><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to &quot;结果&quot;">​</a></h2><p>通常会修改已有页面文件，例如：</p><ul><li><code>apps/&lt;app&gt;/src/views/.../*.vue</code></li><li><code>apps/&lt;app&gt;/src/views/.../components/*.vue</code>（按需拆分）</li></ul><p>常见结果包括：</p><ul><li>用 <code>KaButton</code>、<code>KaCard</code>、<code>KaModal</code>、<code>KaPagination</code> 等替换现有实现</li><li>优化页面结构与样式</li><li>保留原有业务逻辑、接口调用和权限判断</li><li>让页面更贴近 Kpu-admin 已有页面的交互方式与视觉风格</li></ul>`,17)])])}const m=a(d,[["render",t]]);export{h as __pageData,m as default};
